/* === Compound struct bodies === */
struct xc_Token_s {
    xc_integer_t kind;
    xc_string_t text;
    xc_integer_t line;
};
struct xc_LexState_s {
    xc_integer_t pos;
    xc_integer_t line;
    xc_integer_t col;
};
struct xc_LexStep_s {
    xc_Token_t tok;
    xc_integer_t pos;
    xc_integer_t line;
};
struct xc_PState_s {
    xc_arr_Token_t tokens;
    xc_integer_t pos;
};
struct xc_MatchResult_s {
    xc_PState_t ps;
    xc_bool_t matched;
    xc_string_t text;
};
struct xc_TypeResult_s {
    xc_string_t ctype;
    xc_PState_t ps;
};
struct xc_FieldSpec_s {
    xc_string_t name;
    xc_string_t ctype;
};
struct xc_ParamSpec_s {
    xc_string_t name;
    xc_string_t ctype;
};
struct xc_MethodSpec_s {
    xc_bool_t isAsync;
    xc_string_t kind;
    xc_string_t name;
    xc_string_t params;
    xc_string_t retCtype;
    xc_arr_Token_t bodyTokens;
};
struct xc_TypeSpec_s {
    xc_string_t name;
    xc_bool_t isCompound;
    xc_string_t baseCtype;
    xc_arr_string_t fields;
    xc_bool_t hasWhere;
    xc_string_t whereSrc;
    xc_arr_Token_t whereTokens;
};
struct xc_IfaceSpec_s {
    xc_string_t name;
    xc_arr_string_t extendsNames;
    xc_arr_MethodSpec_t methList;
};
struct xc_DepSpec_s {
    xc_string_t name;
    xc_string_t ctype;
    xc_string_t ifaceName;
    xc_bool_t hasWhen;
    xc_string_t form;
    xc_string_t orAlt;
    xc_arr_Token_t whereTokens;
};
struct xc_ClassSpec_s {
    xc_string_t name;
    xc_arr_string_t implNames;
    xc_arr_DepSpec_t depList;
    xc_arr_MethodSpec_t methList;
};
struct xc_BindSpec_s {
    xc_string_t ifaceName;
    xc_string_t concreteName;
    xc_string_t scopeKind;
};
struct xc_ModuleSpec_s {
    xc_string_t name;
    xc_arr_BindSpec_t bindings;
};
struct xc_FuncSpec_s {
    xc_bool_t isCreator;
    xc_bool_t isAsync;
    xc_string_t kind;
    xc_string_t name;
    xc_string_t params;
    xc_string_t retCtype;
    xc_arr_Token_t bodyTokens;
    xc_bool_t hasWhere;
    xc_arr_Token_t whereTokens;
    xc_arr_DepSpec_t fnDeps;
};
struct xc_Program_s {
    xc_arr_TypeSpec_t types;
    xc_arr_IfaceSpec_t ifaces;
    xc_arr_ClassSpec_t classes;
    xc_arr_ModuleSpec_t modules;
    xc_arr_FuncSpec_t functions;
    xc_arr_FuncSpec_t externs;
    xc_FuncSpec_t entrySpec;
};
struct xc_KindResult_s {
    xc_string_t kind;
    xc_PState_t ps;
    xc_bool_t ok;
};
struct xc_ParamResult_s {
    xc_string_t params;
    xc_PState_t ps;
};
struct xc_RetResult_s {
    xc_string_t ctype;
    xc_PState_t ps;
};
struct xc_BodyResult_s {
    xc_arr_Token_t bodyTokens;
    xc_PState_t ps;
};
struct xc_FuncResult_s {
    xc_FuncSpec_t spec;
    xc_PState_t ps;
};
struct xc_SigResult_s {
    xc_MethodSpec_t spec;
    xc_PState_t ps;
};
struct xc_TypeResult2_s {
    xc_TypeSpec_t spec;
    xc_PState_t ps;
};
struct xc_IfaceResult_s {
    xc_IfaceSpec_t spec;
    xc_PState_t ps;
};
struct xc_DepResult_s {
    xc_DepSpec_t spec;
    xc_PState_t ps;
};
struct xc_ClassResult_s {
    xc_ClassSpec_t spec;
    xc_PState_t ps;
};
struct xc_ModuleResult_s {
    xc_ModuleSpec_t spec;
    xc_PState_t ps;
};
struct xc_ExprRes_s {
    xc_string_t code;
    xc_integer_t pos;
    xc_string_t xtyp;
};
struct xc_GArgs_s {
    xc_string_t code;
    xc_integer_t pos;
    xc_string_t firstRaw;
};
struct xc_GCtx_s {
    xc_Program_t prog;
    xc_arr_string_t symNames;
    xc_arr_string_t symTypes;
    xc_arr_string_t depNames;
    xc_arr_string_t depTypes;
    xc_string_t retCtype;
};
struct xc_StmtRes_s {
    xc_string_t code;
    xc_GCtx_t ctx;
    xc_integer_t pos;
};
struct xc_LoadResult_s {
    xc_arr_Token_t tokens;
    xc_arr_string_t visited;
    xc_arr_string_t qnames;
    xc_arr_string_t qrepl;
};

