static xc_arr_Token_t xc_tokenise(xc_string_t src) {
    __auto_type slen = string_len(src);
    xc_arr_Token_t tokens = {0};
    __auto_type p = 0LL;
    __auto_type ln = 1LL;
    __auto_type running = true;
    __auto_type prevKind = 0LL;
    while (running) {
    __auto_type step = xc_lexOne(src, p, ln, prevKind);
    p = step.pos;
    ln = step.line;
    if ((step.tok.kind == 0LL)) {
    running = false;
    } else {
    tokens = xc_appendToken(tokens, step.tok);
    prevKind = step.tok.kind;
    }
    }
    tokens = xc_appendToken(tokens, (xc_Token_t){ .kind = 0LL, .text = xc_string_from_cstr(""), .line = ln });
    return tokens;
}

