static xc_ParamResult_t xc_parseParams(xc_PState_t ps) {
    xc_arr_string_t parts = {0};
    __auto_type ps2 = ps;
    __auto_type running = true;
    while (((running && (xc_peek(ps2).kind != 101LL)) && (xc_peek(ps2).kind != 0LL))) {
    __auto_type nameTok = xc_peek(ps2);
    if ((nameTok.kind != 1LL)) {
    ps2 = xc_advance(ps2);
    } else {
    ps2 = xc_advance(ps2);
    if ((xc_peek(ps2).kind == 108LL)) {
    ps2 = xc_advance(ps2);
    }
    __auto_type tr = xc_parseTypeExpr(ps2);
    ps2 = tr.ps;
    __auto_type paramStr = xc_string_concat(xc_string_concat(tr.ctype, xc_string_from_cstr(" ")), nameTok.text);
    parts = appendString(parts, paramStr);
    if ((xc_peek(ps2).kind == 106LL)) {
    ps2 = xc_advance(ps2);
    }
    }
    }
    __auto_type result = xc_string_from_cstr("");
    __auto_type i = 0LL;
    __auto_type plen = stringArrLen(parts);
    while ((i < plen)) {
    if ((i > 0LL)) {
    result = xc_string_concat(result, xc_string_from_cstr(", "));
    }
    result = xc_string_concat(result, stringArrGet(parts, i));
    i = (i + 1LL);
    }
    return (xc_ParamResult_t){ .params = result, .ps = ps2 };
}

